def diagnose_simpo(
    reward_margins: list[float],  # r_w - r_l per step
    accuracies: list[float],      # fraction(r_w > r_l) per step
    gamma: float,
) -> dict[str, str]:
    issues = {}

    # Reward accuracy should approach but not instantly reach 1.0
    if accuracies[-1] > 0.98 and accuracies[5] > 0.95:
        issues['gamma_too_small'] = (
            'Accuracy saturated at 1.0 immediately. Increase gamma to force a harder margin.'
        )

    # Margin should grow and then stabilise above gamma
    mean_margin = sum(reward_margins[-20:]) / 20
    if mean_margin < gamma:
        issues['margin_below_gamma'] = (
            f'Mean reward margin {mean_margin:.3f} below gamma {gamma}. '
            'Loss is still active. Consider increasing beta or reducing gamma.'
        )

    # Margins should not explode (reward hacking toward extreme distributions)
    if max(reward_margins) > 10 * gamma:
        issues['reward_hacking'] = (
            'Reward margins exploding. The model may be collapsing to repetitive or'
            ' trivially high-probability responses. Reduce beta or add regularisation.'
        )

    if not issues:
        issues['status'] = 'Training healthy: margin growing and stabilising above gamma.'
    return issues
